    // ---------------------------------------------------------------------
    // UploadAsync — uploaded file name sanitization (path-traversal /
    // arbitrary file-write hardening).
    //
    // IFormFile.FileName is entirely client-controlled, so it must be treated
    // as untrusted. The vulnerable implementation combined it verbatim with
    // the resolved directory and wrote wherever the resulting path resolved,
    // letting a name like "../escape.txt" or an absolute path place a file
    // outside the home sandbox. The hardened implementation must either reject
    // such names with ArgumentException or strip them to a safe leaf and write
    // strictly inside the root — but in NO case may a file appear outside it.
    // These tests pin that contract and fail against the vulnerable code.
    // ---------------------------------------------------------------------

    /// <summary>
    /// The headline regression: a parent-traversal sequence in the uploaded
    /// file name must never write outside the home root. The vulnerable
    /// <c>Path.Combine(root, "../escape.txt")</c> resolves one level above
    /// <c>Home</c> (into the content root) and creates a file there.
    /// </summary>
    [Fact]
    public async Task UploadAsync_FileNameWithParentTraversal_DoesNotWriteOutsideRoot()
    {
        var (service, root) = CreateService();
        // The OS-resolved location the vulnerable code would write to.
        var escapeTarget = Path.GetFullPath(Path.Combine(root, "..", "escape.txt"));
        Assert.False(File.Exists(escapeTarget));

        var file = FormFileFactory.CreateFormFile("../escape.txt", "x");
        try
        {
            await service.UploadAsync("", file);
        }
        catch (ArgumentException)
        {
            // A rejecting implementation also satisfies the contract; the
            // assertion below is the real guarantee.
        }

        Assert.False(File.Exists(escapeTarget),
            $"uploaded file escaped the home root to {escapeTarget}");
    }

    /// <summary>
    /// Same property for a deeper traversal (the example from the security
    /// finding). The escape target lands outside the per-test content root, so
    /// it is cleaned up explicitly to avoid polluting the repo between runs.
    /// </summary>
    [Fact]
    public async Task UploadAsync_FileNameWithMultipleParentTraversal_DoesNotWriteOutsideRoot()
    {
        var (service, root) = CreateService();
        var escapeTarget = Path.GetFullPath(Path.Combine(root, "..", "..", "escape.txt"));
        Assert.False(File.Exists(escapeTarget));

        var file = FormFileFactory.CreateFormFile("../../escape.txt", "x");
        try
        {
            try
            {
                await service.UploadAsync("", file);
            }
            catch (ArgumentException)
            {
                // rejection is acceptable
            }

            Assert.False(File.Exists(escapeTarget),
                $"uploaded file escaped the home root to {escapeTarget}");
        }
        finally
        {
            // The escape target is outside the per-test content root and would
            // not be removed by Dispose, so clean it up to avoid polluting the
            // repository between runs (in case a regression ever writes here).
            if (File.Exists(escapeTarget))
            {
                File.Delete(escapeTarget);
            }
        }
    }

